var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"허억…!","JPN":"はあっ……！","ENG":"*Gasp…!*","TWN":"哈啊…！"},"stage":{"bg":"VOID","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"쿨럭, 쿨럭…","JPN":"ゲホッ、ゲホッ……","ENG":"*Cough* *Cough…*","TWN":"咳、咳咳…"},"stage":{"bg":"VOID","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_HATE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"여긴 어디지?","JPN":"ここはどこだ？","ENG":"Where am I?","TWN":"這裡是哪裡？"},"stage":{"bg":"VOID","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"너는 범에게 먹혔다.","JPN":"お前は虎に食われた。","ENG":"You were devoured by the Tiger.","TWN":"你被老虎給吞了。"},"stage":{"bg":"VOID","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"이곳은 먹으로 가득 들어찬 범의 뱃속이지.","JPN":"そしてここは、墨に満ちた虎の腹の中だ。","ENG":"This is the Tiger's belly, filled to the brim with Ink.","TWN":"這裡是被墨充滿的老虎肚子裡。"},"stage":{"bg":"VOID","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L10_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"VOID","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"보여선 안 될 것이 보이는데, 내가 아직도 꿈을 꾸는 거요?","JPN":"見えるはずのない存在が見えるのだが、某はまだ夢を見ているのか？","ENG":"I'm seeing something that shouldn't exist… Am I still dreaming?","TWN":"看到了不該看的東西，我還在做夢嗎？"},"stage":{"bg":"VOID","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L12_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"네 혼백이 녹아내려 먹과 하나될 때까지, 영영 꿈만 꿀 수도 있었을 테지.","JPN":"お前の魂魄が溶け落ち墨と一つになるまで、永遠に夢を見ることだってできたわけだが……","ENG":"You might have dreamed forever until your soul melted away and merged with the Ink.","TWN":"在你的魂魄融化與墨合為一體之前，你本來可以永遠做夢下去。"},"stage":{"bg":"VOID","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"그래도 깨어난 것을 보면, 내가 남겨논 문장이 쓸모는 있었던 모양이구나.","JPN":"それでも目覚めたということは、俺が残した文はちゃんと役に立ったようだな。","ENG":"But since you've woken, I suppose the text I left behind did its job.","TWN":"不過看你醒了，看來我留下的文字還是有點用處。"},"stage":{"bg":"VOID","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L14_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"정말 살아있는 사람이 맞소?","JPN":"本当に生きている人間なのか？","ENG":"Are you truly alive?","TWN":"你真的是活人嗎？"},"stage":{"bg":"VOID","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L15_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"정녕 네놈 앞에 있는 게 창귀로 보이느냐?","JPN":"お前の目の前にいるのが、倀鬼に見えるか？","ENG":"Do I look like a ghost thrall to you?","TWN":"你真的把眼前的我當成是倀鬼嗎？"},"stage":{"bg":"VOID","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L16_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…명달 대장이 창귀였다면, 지금쯤 내 두 눈을 찔렀겠지.","JPN":"……アカタツ隊長が倀鬼になったら、今頃某の両目は刺されていたであろう。","ENG":"…If you were one, you'd have gouged out my eyes by now.","TWN":"…如果明達隊長是倀鬼，現在早就刺瞎我的雙眼了。"},"stage":{"bg":"VOID","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L17_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"난… 대장이 죽은 줄로만 알았소.","JPN":"某は……隊長は死んだのだと思っていた。","ENG":"I thought… you were dead.","TWN":"我…還以為隊長已經死了。"},"stage":{"bg":"VOID","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L18_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"내 말하지 않았느냐? 호랑이 뱃속에 들어가도 정신만 차리면…","JPN":"だから言っただろう？　虎に食われても気をしっかり保てば……","ENG":"Didn't I tell you? Even if I end up in its belly, so long as I keep my wits…","TWN":"我不是說過嗎？就算進了老虎肚子裡，只要打起精神…"},"stage":{"bg":"VOID","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…10년은 버티는 법이라고 하셨지.","JPN":"……10年は行ける、とな。","ENG":"…That you'd hold out for ten years.","TWN":"…就能撐十年，你是這麼說的。"},"stage":{"bg":"VOID","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"범의 뱃속에선 먹힌 자의 살아온 세월이 놈의 양분이 된다.","JPN":"虎の腹の中では、食われた者の生きた年月がやつの糧となる。","ENG":"Within the Tiger's belly, your years lived become its nourishment.","TWN":"在老虎肚子裡，被吞者的歲月會成為牠的養分。"},"stage":{"bg":"VOID","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L21_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"보통 사람이라면 며칠 새로 먹이 되었겠지만, 내 살아온 세월을 전부 놈의 양분으로 삼으려면 족히 10년은 걸리지.","JPN":"普通の人間なら数日で墨になっていただろうが、俺の生きてきた時間をすべてやつの糧に変えるには、10年はかかる。","ENG":"A normal person would've been digested into Ink in days, but it'd take at least ten years to digest the whole of my life.","TWN":"普通人可能幾天內就會變成飼料，但要將我活過的歲月全部當成養分，大概得花上十年。"},"stage":{"bg":"VOID","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"과연, 허투루 하는 말씀이 아니었구려.","JPN":"なるほど、適当な話ではなかったのだな。","ENG":"So you weren't bluffing after all.","TWN":"果然，你的話從來都不是隨口說說。"},"stage":{"bg":"VOID","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"허나 내가 아무리 버텨낸다 한들, 네놈이 오지 않았다면 난 깨어나지 못했을 거다.","JPN":"しかし俺がいくら耐えられたところで、お前が来てくれなかったら目覚めることはできなかっただろう。","ENG":"Still, no matter how long I held out, I wouldn't have awakened if you hadn't come.","TWN":"然而，就算我再怎麼撐，如果不是你來，我也不可能醒來。"},"stage":{"bg":"VOID","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"…잘 해주었구나.","JPN":"……よくやってくれた。","ENG":"…You did well.","TWN":"…你做得很好。"},"stage":{"bg":"VOID","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L25_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"VOID","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L26_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"고맙소. 본인을 믿고 견뎌주어서.","JPN":"感謝する。某を信じて耐えてくれて。","ENG":"Thank you. For enduring and believing in me.","TWN":"謝謝你。相信我並撐下來。"},"stage":{"bg":"VOID","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L29_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"그럼 가자꾸나.","JPN":"では行こうか。","ENG":"Then let's be off.","TWN":"那麼走吧。"},"stage":{"bg":"VOID","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"아늑한 꿈을 벗어나 지옥 같은 현실을 마주할 준비는 되었느냐?","JPN":"心地良い夢から出て、地獄のような現実と向き合う覚悟はできているか？","ENG":"Are you ready to leave your cozy dream behind and face a living hell?","TWN":"準備好離開舒適的夢境，面對如同地獄般的現實了嗎？"},"stage":{"bg":"VOID","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"꿈 같은 건, 이제 지긋지긋하다네.","JPN":"夢はもう懲り懲りだ。","ENG":"I'm sick of dreams.","TWN":"夢這種東西，我已經受夠了。"},"stage":{"bg":"VOID","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"VOID","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};